    jinMap.get(cat).push(i);
}

const xiaoMap = new Map();
for (let i = 1; i < data2.length; i++) {
    const name = data2[i][11] || '';
    if (!name) continue;
    const cat = extractCategory(name);
    if (!cat) continue;
    if (!xiaoMap.has(cat)) xiaoMap.set(cat, []);
    xiaoMap.get(cat).push(i);
}

const jinCats = new Set(jinMap.keys());
const xiaoCats = new Set(xiaoMap.keys());

// 提取仅在销项中的品类，看看有没有和进项相似的
const onlyXiao = [...xiaoCats].filter(k => !jinCats.has(k));

// 计算两个字符串的相似度 (简单版：最长公共子序列比例)
function similarity(a, b) {
    if (!a || !b) return 0;
    const s1 = a.toLowerCase();
    const s2 = b.toLowerCase();
    // 如果一个是另一个的子串（较长串的60%以上）
    if (s1.includes(s2)) return s2.length / Math.max(s1.length, s2.length);
    if (s2.includes(s1)) return s1.length / Math.max(s1.length, s2.length);
    // Jaccard相似度：基于字符
    const set1 = new Set(s1);
    const set2 = new Set(s2);
    const intersection = new Set([...set1].filter(c => set2.has(c)));
    const union = new Set([...set1, ...set2]);
    return intersection.size / union.size;
}

