const XLSX = require('xlsx');
const path = require('path');
const fs = require('fs');

const DESKTOP = 'C:\\Users\\Administrator\\Desktop';
const OUTPUT_FILE = path.join(DESKTOP, '进销项对比分析结果.xlsx');

// ====== 1. READ ALL FILES ======
console.log('正在读取文件...');

const wbJin = XLSX.readFile(path.join(DESKTOP, '壹仕通25年进项.xlsx'));
const wbXiao = XLSX.readFile(path.join(DESKTOP, '壹仕通25年销项.xlsx'));
const wbRef = XLSX.readFile(path.join(DESKTOP, '过滤条件及关键词库.xlsx'));

function readSheetData(wb, sheetName) {
    const ws = wb.Sheets[sheetName];
    if (!ws) return [];
    return XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
}

const jinRows = readSheetData(wbJin, '信息汇总表');
const xiaoRows = readSheetData(wbXiao, '信息汇总表');
const filterRows = readSheetData(wbRef, '过滤条件');
const keywordRows = readSheetData(wbRef, '关键词库');
const unitRows = readSheetData(wbRef, '单位换算');

// ====== 2. BUILD REFERENCE DATA ======

// 过滤条件列表
const filterList = filterRows.slice(1).map(r => r[0]).filter(Boolean).map(v => v.toString().trim());

// 关键词库：存为Set (Column B = 标准关键词)
const keywordSet = new Set();
for (let i = 1; i < keywordRows.length; i++) {
    const kw = keywordRows[i][1];
    if (kw) keywordSet.add(kw.toString().trim());
}

// 关键词库：A列→B列映射 (for matching)
const keywordMap = new Map();
for (let i = 1; i < keywordRows.length; i++) {
    const colA = keywordRows[i][0];
    const colB = keywordRows[i][1];
    if (colA && colB) keywordMap.set(colA.toString().trim(), colB.toString().trim());
}

// 单位换算表：(product, fromUnit) → {toUnit, rate}
const unitMap = new Map();
for (let i = 1; i < unitRows.length; i++) {
    const r = unitRows[i];
    const prod = r[0] ? r[0].toString().trim() : '';
    const fromUnit = r[1] ? r[1].toString().trim() : '';
    const toUnit = r[2] ? r[2].toString().trim() : '';
    const rate = parseFloat(r[3]) || 1;
    if (prod && fromUnit && toUnit) {
        const key = prod + '||' + fromUnit;
        unitMap.set(key, { toUnit, rate });
    }
}

// ====== 3. HELPER FUNCTIONS ======

// 提取品类名：取最后一个*后面的内容
function extractCategory(name) {
    if (!name) return '';
    const s = name.toString().trim();
    if (!s) return '';
    const parts = s.split('*');
    return parts[parts.length - 1].trim();
}

// 判断是否应该被过滤掉
function shouldFilter(name, cat) {
    if (!name && !cat) return true;
    const check = [name.toString(), cat].filter(Boolean);
    return check.some(c => filterList.some(f => c.includes(f)));
}

// 标准关键词匹配：对提取的品类名，尝试找关键词库标准词
function getStandardKeyword(category) {
    if (!category) return category;
    // 1. 精确匹配关键词库B列
    if (keywordSet.has(category)) return category;
    // 2. 如果品类本身就是某个关键词的一部分，且该关键词在B列中
    // 例如 "彩色回形针" → 检查关键词库中是否有 "彩色回形针"
    // 这已经被上一步覆盖了

    return category; // 没找到就返回原名称
}

// Bigram Dice相似度
function similarity(a, b) {
    if (!a || !b) return 0;
    if (a === b) return 1;
    const s1 = a.toLowerCase();
    const s2 = b.toLowerCase();
    const bigrams1 = new Set();
    const bigrams2 = new Set();
    for (let i = 0; i < s1.length - 1; i++) bigrams1.add(s1.substring(i, i + 2));
    for (let i = 0; i < s2.length - 1; i++) bigrams2.add(s2.substring(i, i + 2));
    if (bigrams1.size === 0 || bigrams2.size === 0) return 0;
    let intersection = 0;
    for (const b of bigrams1) if (bigrams2.has(b)) intersection++;
    return 2 * intersection / (bigrams1.size + bigrams2.size);
}

// 匹配规则：判断两个品类名是否指向同一类产品
function namesMatch(name1, name2) {
    if (!name1 || !name2) return null;
    const n1 = name1.toString().trim();
    const n2 = name2.toString().trim();
    if (!n1 || !n2) return null;

    // 1. 精确匹配
    if (n1 === n2) return '精确匹配';

    // 2. 从属匹配：A包含B且B在关键词库中
    if (n1.includes(n2) && keywordSet.has(n2)) return '从属匹配';
    if (n2.includes(n1) && keywordSet.has(n1)) return '从属匹配';

    // 3. 85%相似度匹配
    const sim = similarity(n1, n2);
    if (sim >= 0.85) return '相似度匹配';

    return null;
}

// 单位换算：对一行数据，尝试换算为标准单位
function convertUnit(category, spec, origUnit, qty) {
    if (!origUnit || !qty) return { unit: origUnit, qty: qty, converted: false };

    const u = origUnit.toString().trim();
    if (!u) return { unit: origUnit, qty: qty, converted: false };

    // 尝试多种方式匹配单位换算表
    // 方式1: (品类名, 原单位) 精确匹配
    let key = category + '||' + u;
    if (unitMap.has(key)) {
        const rule = unitMap.get(key);
        return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
    }

    // 方式2: (规格型号中的产品名, 原单位) 匹配
    if (spec) {
        // 尝试用规格型号中的关键词匹配单位换算表的产品名
        for (const [mapKey, rule] of unitMap) {
            const [prod, unit] = mapKey.split('||');
            if (unit === u && spec.toString().includes(prod)) {
                return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
            }
        }
    }

    // 方式3: 品类名是换算表产品名的子串
    for (const [mapKey, rule] of unitMap) {
        const [prod, unit] = mapKey.split('||');
        if (unit === u && prod.includes(category)) {
            return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
        }
    }

    return { unit: origUnit, qty: qty, converted: false };
}

// ====== 4. EXTRACT AND PARSE ALL DATA ======

// 列索引：L=11, M=12, N=13, O=14, P=15
const COL = { name: 11, spec: 12, unit: 13, qty: 14, price: 15, invoiceNo: 3, date: 8, buyer: 7, seller: 5, note: 26 };

function parseRows(rows, source) {
    const result = [];
    for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        const rawName = row[COL.name] ? row[COL.name].toString().trim() : '';
        if (!rawName) continue;

        const category = extractCategory(rawName);
        if (!category || shouldFilter(rawName, category)) continue;

        const spec = row[COL.spec] ? row[COL.spec].toString().trim() : '';
        const origUnit = row[COL.unit] ? row[COL.unit].toString().trim() : '';
        const rawQty = parseFloat(row[COL.qty]) || 0;
        const rawPrice = parseFloat(row[COL.price]) || 0;
        const invoiceNo = row[COL.invoiceNo] ? row[COL.invoiceNo].toString().trim() : '';
        const date = row[COL.date] ? row[COL.date].toString().trim() : '';
        const note = row[COL.note] ? row[COL.note].toString().trim() : '';

        // 单位换算
        const conv = convertUnit(category, spec, origUnit, rawQty);

        // 找标准关键词
        const keyword = getStandardKeyword(category);

        result.push({
            rowNum: i,
            source,
            rawName,
            category,
            keyword,
            spec,
            origUnit,
            unit: conv.unit,
            origQty: rawQty,
            qty: conv.qty,
            price: rawPrice,
            convRate: conv.rate || 1,
            converted: conv.converted,
            invoiceNo,
            date,
            note
        });
    }
    return result;
}

console.log('正在解析数据...');
const jinData = parseRows(jinRows, '进项');
const xiaoData = parseRows(xiaoRows, '销项');
console.log(`进项有效行数: ${jinData.length}, 销项有效行数: ${xiaoData.length}`);

// ====== 5. PRODUCT GROUPING ======

// 获取所有唯一品类名
function getUniqueCategories(data) {
    return [...new Set(data.map(d => d.category))];
}

const jinCats = getUniqueCategories(jinData);
const xiaoCats = getUniqueCategories(xiaoData);

console.log(`进项品类数: ${jinCats.length}, 销项品类数: ${xiaoCats.length}`);

// 构建匹配关系：品类名→产品组ID
// 使用并查集(Union-Find)进行分组
class UnionFind {
    constructor() {
        this.parent = new Map();
    }
    find(x) {
        if (!this.parent.has(x)) this.parent.set(x, x);
        if (this.parent.get(x) !== x) {
            this.parent.set(x, this.find(this.parent.get(x)));
        }
        return this.parent.get(x);
    }
    union(x, y) {
        const px = this.find(x);
        const py = this.find(y);
        if (px !== py) this.parent.set(px, py);
    }
}

const uf = new UnionFind();

// 先注册所有品类名
[...jinCats, ...xiaoCats].forEach(c => uf.find(c));

// 匹对进项和销项的品类名
let exactCount = 0, containCount = 0, simCount = 0;
for (const jCat of jinCats) {
    for (const xCat of xiaoCats) {
        const matchType = namesMatch(jCat, xCat);
        if (matchType) {
            uf.union(jCat, xCat);
            if (matchType === '精确匹配') exactCount++;
            else if (matchType === '从属匹配') containCount++;
            else simCount++;
        }
    }
}

console.log(`匹配结果: 精确匹配=${exactCount}, 从属匹配=${containCount}, 相似度匹配=${simCount}`);

// 构建产品组
const groupMap = new Map(); // root → groupId
const groups = []; // { id, jinNames: Set, xiaoNames: Set }

for (const c of [...new Set([...jinCats, ...xiaoCats])]) {
    const root = uf.find(c);
    if (!groupMap.has(root)) {
        const groupId = groups.length + 1;
        groupMap.set(root, groupId);
        groups.push({ id: groupId, jinNames: new Set(), xiaoNames: new Set() });
    }
    const g = groups[groupMap.get(root) - 1];
    if (jinCats.includes(c)) g.jinNames.add(c);
    if (xiaoCats.includes(c)) g.xiaoNames.add(c);
}

// 为每个品类名分配组ID
const catToGroup = new Map();
for (const [root, gid] of groupMap) {
    for (const c of [...new Set([...jinCats, ...xiaoCats])]) {
        if (uf.find(c) === root) catToGroup.set(c, gid);
    }
}

console.log(`产品组数: ${groups.length}`);

// 标记未匹配的品类
const matchedJin = new Set();
const matchedXiao = new Set();
for (const g of groups) {
    for (const jn of g.jinNames) matchedJin.add(jn);
    for (const xn of g.xiaoNames) matchedXiao.add(xn);
}
const unmatchedJin = jinCats.filter(c => !matchedJin.has(c));
const unmatchedXiao = xiaoCats.filter(c => !matchedXiao.has(c));

// 将未匹配的产品各自单独成组
for (const c of unmatchedJin) {
    const gid = groups.length + 1;
    catToGroup.set(c, gid);
    groups.push({ id: gid, jinNames: new Set([c]), xiaoNames: new Set() });
}
for (const c of unmatchedXiao) {
    const gid = groups.length + 1;
    catToGroup.set(c, gid);
    groups.push({ id: gid, jinNames: new Set(), xiaoNames: new Set([c]) });
}

// 为每行数据分配组ID
for (const d of jinData) d.groupId = catToGroup.get(d.category) || 0;
for (const d of xiaoData) d.groupId = catToGroup.get(d.category) || 0;

// ====== 6. BUILD COMPARISON DATA ======

// --- Sheet 1: 数量汇总对比 ---
// 每个产品组+单位对比数量
function buildQtyComparison(groups, jinData, xiaoData) {
    const rows = [];

    for (const g of groups) {
        // 用进项+销项所有出现过的单位
        const jinUnits = new Map(); // unit → totalQty
        const xiaoUnits = new Map(); // unit → totalQty

        const gJinData = jinData.filter(d => d.groupId === g.id);
        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);

        for (const d of gJinData) {
            jinUnits.set(d.unit, (jinUnits.get(d.unit) || 0) + d.qty);
        }
        for (const d of gXiaoData) {
            xiaoUnits.set(d.unit, (xiaoUnits.get(d.unit) || 0) + d.qty);
        }

        // 进项名称和销项名称展示
        const jinNames = [...g.jinNames].join('; ');
        const xiaoNames = [...g.xiaoNames].join('; ');

        // 所有涉及的单位
        const allUnits = new Set([...jinUnits.keys(), ...xiaoUnits.keys()]);

        for (const unit of allUnits) {
            const jinQty = jinUnits.get(unit) || 0;
            const xiaoQty = xiaoUnits.get(unit) || 0;
            const diff = jinQty - xiaoQty;
            rows.push({
                产品组编号: g.id,
                进项品类: jinNames || '—',
                销项品类: xiaoNames || '—',
                单位: unit,
                进项总数量: Math.round(jinQty * 100) / 100,
                销项总数量: Math.round(xiaoQty * 100) / 100,
                数量差异: Math.round(diff * 100) / 100,
                说明: jinQty > 0 && xiaoQty > 0 ? '' : (jinQty > 0 ? '仅有进项' : '仅有销项')
            });
        }
    }
    return rows;
}

// --- Sheet 2: 单价异常明细 ---
// 进项单价 > 销项单价的异常行
function buildPriceAnomalies(groups, jinData, xiaoData) {
    const rows = [];

    for (const g of groups) {
        const gJinData = jinData.filter(d => d.groupId === g.id);
        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);

        if (gJinData.length === 0 || gXiaoData.length === 0) continue;

        // 收集销项所有去重单价
        const xiaoPrices = [...new Set(gXiaoData.map(d => d.price))].sort((a, b) => a - b);
        // 收集进项所有去重单价
        const jinPrices = [...new Set(gJinData.map(d => d.price))].sort((a, b) => a - b);

        if (xiaoPrices.length === 0 || jinPrices.length === 0) continue;

        const xiaoMin = xiaoPrices[0];
        const jinMax = jinPrices[jinPrices.length - 1];

        // 检查：进项最大单价 > 销项最小单价
        if (jinMax > xiaoMin) {
            // 标记进项中单价 > 销项最小单价的那些行
            for (const d of gJinData) {
                if (d.price > xiaoMin) {
                    rows.push({
                        来源: '进项',
                        产品组: g.id,
                        进项品类: d.category,
                        销项品类: [...g.xiaoNames].join('; '),
                        发票号码: d.invoiceNo,
                        开票日期: d.date,
                        单位: d.unit,
                        数量: d.qty,
                        单价: d.price,
                        销项最低单价: xiaoMin,
                        差异: Math.round((d.price - xiaoMin) * 100) / 100,
                        异常说明: `进项单价${d.price} > 销项最低单价${xiaoMin}`
                    });
                }
            }

            // 标记销项中单价 < 进项最大单价的行
            for (const d of gXiaoData) {
                if (d.price < jinMax) {
                    rows.push({
                        来源: '销项',
                        产品组: g.id,
                        进项品类: [...g.jinNames].join('; '),
                        销项品类: d.category,
                        发票号码: d.invoiceNo,
                        开票日期: d.date,
                        单位: d.unit,
                        数量: d.qty,
                        单价: d.price,
                        进项最高单价: jinMax,
                        差异: Math.round((jinMax - d.price) * 100) / 100,
                        异常说明: `销项单价${d.price} < 进项最高单价${jinMax}`
                    });
                }
            }
        }
    }
    return rows;
}

// --- Sheet 3: 单价全览 ---
function buildPriceOverview(groups, jinData, xiaoData) {
    const rows = [];
    for (const g of groups) {
        const gJinData = jinData.filter(d => d.groupId === g.id);
        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);

        if (gJinData.length === 0 && gXiaoData.length === 0) continue;

        const jinNames = [...g.jinNames].join('; ') || '—';
        const xiaoNames = [...g.xiaoNames].join('; ') || '—';

        // 进项所有单价(去重排序)
        const jinPrices = [...new Set(gJinData.map(d => d.price))].sort((a, b) => a - b);
        // 销项所有单价(去重排序)
        const xiaoPrices = [...new Set(gXiaoData.map(d => d.price))].sort((a, b) => a - b);

        const jinMin = jinPrices.length > 0 ? jinPrices[0] : '—';
        const jinMax = jinPrices.length > 0 ? jinPrices[jinPrices.length - 1] : '—';
        const xiaoMin = xiaoPrices.length > 0 ? xiaoPrices[0] : '—';
        const xiaoMax = xiaoPrices.length > 0 ? xiaoPrices[xiaoPrices.length - 1] : '—';

        // 是否有异常
        const hasAnomaly = (jinMax !== '—' && xiaoMin !== '—' && parseFloat(jinMax) > parseFloat(xiaoMin));
        const jinRows = gJinData.length;
        const xiaoRows = gXiaoData.length;

        rows.push({
            产品组编号: g.id,
            进项品类: jinNames,
            进项行数: jinRows,
            进项单价列表: jinPrices.join(', '),
            进项最低单价: jinMin,
            进项最高单价: jinMax,
            销项品类: xiaoNames,
            销项行数: xiaoRows,
            销项单价列表: xiaoPrices.join(', '),
            销项最低单价: xiaoMin,
            销项最高单价: xiaoMax,
            状态: hasAnomaly ? '⚠ 有异常' : (jinRows > 0 && xiaoRows > 0 ? '✓ 正常' : (jinRows > 0 ? '仅进项' : '仅销项'))
        });
    }
    return rows;
}

// --- Sheet 4: 匹配明细 ---
function buildMatchDetail(groups) {
    const rows = [];
    for (const g of groups) {
        const jinNames = [...g.jinNames];
        const xiaoNames = [...g.xiaoNames];

        // 找出配对方式
        for (const jn of jinNames) {
            for (const xn of xiaoNames) {
                const matchType = namesMatch(jn, xn);
                rows.push({
                    产品组编号: g.id,
                    进项品类: jn,
                    销项品类: xn,
                    匹配方式: matchType || '—'
                });
            }
        }

        // 未匹配到的
        for (const jn of jinNames) {
            let hasMatch = false;
            for (const xn of xiaoNames) {
                if (namesMatch(jn, xn)) { hasMatch = true; break; }
            }
            if (!hasMatch) {
                rows.push({
                    产品组编号: g.id,
                    进项品类: jn,
                    销项品类: '—',
                    匹配方式: '未匹配到销项'
                });
            }
        }
        for (const xn of xiaoNames) {
            let hasMatch = false;
            for (const jn of jinNames) {
                if (namesMatch(jn, xn)) { hasMatch = true; break; }
            }
            if (!hasMatch) {
                rows.push({
                    产品组编号: g.id,
                    进项品类: '—',
                    销项品类: xn,
                    匹配方式: '未匹配到进项'
                });
            }
        }
    }
    return rows;
}

// ====== 7. GENERATE OUTPUT ======
console.log('正在生成对比结果...');

const qtyRows = buildQtyComparison(groups, jinData, xiaoData);
const priceAnomalyRows = buildPriceAnomalies(groups, jinData, xiaoData);
const priceOverviewRows = buildPriceOverview(groups, jinData, xiaoData);
const matchRows = buildMatchDetail(groups);

console.log(`数量对比行数: ${qtyRows.length}`);
console.log(`单价异常行数: ${priceAnomalyRows.length}`);
console.log(`单价全览行数: ${priceOverviewRows.length}`);
console.log(`匹配明细行数: ${matchRows.length}`);

// 写入Excel
const wbOut = XLSX.utils.book_new();

const ws1 = XLSX.utils.json_to_sheet(qtyRows);
XLSX.utils.book_append_sheet(wbOut, ws1, '数量汇总对比');

const ws2 = XLSX.utils.json_to_sheet(priceAnomalyRows);
XLSX.utils.book_append_sheet(wbOut, ws2, '单价异常明细');

const ws3 = XLSX.utils.json_to_sheet(priceOverviewRows);
XLSX.utils.book_append_sheet(wbOut, ws3, '单价全览');

const ws4 = XLSX.utils.json_to_sheet(matchRows);
XLSX.utils.book_append_sheet(wbOut, ws4, '匹配明细');

// 调整列宽
function autoColWidth(sheet, data) {
    if (!data || data.length === 0) return;
    const colWidths = {};
    const headers = Object.keys(data[0]);
    headers.forEach((h, i) => {
        colWidths[i] = Math.max(h.length * 2, 10);
    });
    data.forEach(row => {
        Object.values(row).forEach((val, i) => {
            const len = String(val).length * 2;
            if (len > colWidths[i]) colWidths[i] = Math.min(len, 80);
        });
    });
    sheet['!cols'] = Object.values(colWidths).map(w => ({ wch: w }));
}

autoColWidth(ws1, qtyRows);
autoColWidth(ws2, priceAnomalyRows);
autoColWidth(ws3, priceOverviewRows);
autoColWidth(ws4, matchRows);

XLSX.writeFile(wbOut, OUTPUT_FILE);
console.log(`\n完成！输出文件: ${OUTPUT_FILE}`);

