    function isSuffixMatch(longer, shorter) {
        return longer.endsWith(shorter) && keywordSet.has(shorter) && shorter.length >= 2;
    }
    if (n1.length > n2.length && isSuffixMatch(n1, n2)) return '从属匹配';
    if (n2.length > n1.length && isSuffixMatch(n2, n1)) return '从属匹配';

    // 3. 85%相似度匹配
    const sim = similarity(n1, n2);
    if (sim >= 0.85) return '相似度匹配';

    return null;
}

